var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"48시간 전, 그라운드 제로. 침식파 차단 방벽 <color=#ffd34c>밸브</color> 내부.","JPN":"48時間前、グラウンド・ゼロ。侵食波遮断防壁、<color=#ffd34c>バルブ</color>の内部","ENG":"48 hours ago, Ground Zero. Inside the Corruption ray blocking bulwark, <color=#ffd34c>Valve</color>.","TWN":"48小時前，G0。巨型侵蝕波阻擋屏障，<color=#ffd34c>閥門</color>內側。","SCN":"48小时之前，G0。巨型侵蚀波阻挡屏障，<color=#ffd34c>阀门</color>内侧。","DEU":"48 hours ago, Ground Zero. Inside the Corruption ray blocking bulwark, <color=#ffd34c>Valve</color>.","FRA":"48 hours ago, Ground Zero. Inside the Corruption ray blocking bulwark, <color=#ffd34c>Valve</color>."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"힐데, 패러독스","JPN":"ヒルデ、パラドックス","ENG":"Hilde, Paradox","TWN":"希爾德、悖論","SCN":"希尔德，悖论","DEU":"Hilde, Paradox","FRA":"Hilde, Paradox"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"저것들 어떻게 돼먹은 거야?","JPN":"あいつら、いったい何？","ENG":"What's going on with them?","TWN":"那些傢伙到底怎麼回事？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"분명 제압했는데 계속 일어나잖아?!","JPN":"確かに制圧したのに、また立ち上がってる！！","ENG":"We clearly defeated them, but they keep getting back up!","TWN":"明明已經打倒了，怎麼還一直爬起來？！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"저것들, 인간이 아니라 침식체인가?","JPN":"あいつら、人間じゃなくて侵食体なの？","ENG":"Those things, are they C.O.s and not human?","TWN":"那些傢伙不是人類，而是侵蝕體嗎！？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니, 침식체는 저런 식으로 실체를 숨기면서 공격을 흘리지 않아.","JPN":"いや、侵食体はあんな風に実体を隠しながら攻撃したりしない。","ENG":"No. C.O.s don't hide their true nature like that while dodging attacks.","TWN":"不，侵蝕體不會在受到攻擊後還保持偽裝。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"저 특징은… 밴시다.","JPN":"あの特徴……バンシーだ。","ENG":"That is the characteristic... of a banshee.","TWN":"那個是……女妖的特徵。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"밴시?! 그 검은 죽음이 몰고 다니던 성가신 것들?","JPN":"バンシー！？　あの黒い死が連れて歩く厄介者？","ENG":"A banshee?! You mean those pesky things that bring about the Black Death?","TWN":"女妖？！是黑死帶來的那些討厭的東西？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"합의체는 그런 것까지 합성에 성공했단 말이야?","JPN":"合意体はあんなものまで合成することに成功したってこと？","ENG":"You mean to say that the Northern Union succeeded in synthesizing them?","TWN":"北方和議會連那種東西都造出來了嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"호들갑 그만 떨고 바짝 붙어라.","JPN":"騒いでないでしっかりくっついていろ。","ENG":"Stop fussing and stick close.","TWN":"別大驚小怪的，跟上。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"지금부터 빠르게 몰아붙일 테니.","JPN":"今から素早く追い込むぞ。","ENG":"I'm going to start pushing them fast now.","TWN":"現在開始快速推進。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"헥 헥, 계속 달리면 나 죽어. 죽는다구우-","JPN":"ぜえ、ぜえ、これ以上走り続けたら死ぬ。死んじゃうよー","ENG":"*Huff* *Huff* I'm going to die if I keep running...","TWN":"呼、呼，再跑下去我會死的。真的會死——"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그만 징징대고 앞을 봐라.","JPN":"ぐずぐずしていないで、前を見ろ。","ENG":"Stop your whining and look ahead.","TWN":"別再抱怨了，看前面。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"저게 네 녀석이 말한 <color=#ffd34c>정원으로 향하는 우물</color>이겠지?","JPN":"あれがお前の言っていた<color=#ffd34c>庭園に向かう井戸</color>だろう？","ENG":"That must be the <color=#ffd34c>Well to the Garden</color> you mentioned, right?","TWN":"那就是你說的<color=#ffd34c>通往花園的井</color>吧？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아앗, 맞아! 찾았구나!","JPN":"ああっ、そうだよ！　見つけたんだね！","ENG":"Oh! Yes! We found it!","TWN":"啊啊，對的！找到了啊！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"내가 줄을 연결할 테니 뒤를 부탁…!","JPN":"私がロープを繋げるから、後を頼……！","ENG":"I'll connect the line, so cover m–","TWN":"我來連接路線，後面就拜託你了……！"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"콜록 콜록… 폭격?","JPN":"ゲホッ、ゲホッ……爆撃？","ENG":"*Cough* *Cough* ...An explosion?","TWN":"咳咳，咳咳……炮彈？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…아앗! 우물이 부서졌어?","JPN":"……ああっ！　井戸が壊れた？","ENG":"...NO! The Well's been destroyed.","TWN":"……啊啊！井不會壞掉了吧！？"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"안되죠.","JPN":"駄目です。","ENG":"No, you don't.","TWN":"不。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 쉽게 들어가게 두진 않을 겁니다, 펜릴 전대장.","JPN":"そうやって簡単に入れるようにはしません、フェンリル戦隊長。","ENG":"I won't let you go in there so easily, Fenrir Commander.","TWN":"不會讓你這麼輕易過去的，芬里爾戰隊長。"},"stage":{"bg":"COUNTERSIDE_BASE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};